const calculatePi = () => {
  let pi = 0;
  let term = 1;
  let i = 0;
  while (Math.abs(term) > 1e-15) {
    pi += term;
    i++;
    term = (-1) ** i / (2 * i + 1);
  }
  return pi * 4;
};

console.log(calculatePi().toFixed(10));

const calculatePi = () => {
  let pi = 0;
  let term = 1;
  let i = 0;
  while (Math.abs(term) > 1e-15) {
    pi += term;
    i++;
    term = (-1) ** i / (2 * i + 1);
  }
  return pi * 4;
};

console.log(calculatePi().toFixed(15));

function calculatePi(iterations = 1000000) {
  let pi = 0;
  for (let i = 0; i < iterations; i++) {
    pi += 4 / (8 * i + 1) - 4 / (8 * i + 5) - 2 / (8 * i + 6) - 4 / (8 * i + 7);
  }
  return pi;
}

console.log(calculatePi().toFixed(15));

function calculatePi(iterations) {
  let pi = 0;
  for (let i = 0; i < iterations; i++) {
    pi += Math.pow(-1, i) / (2 * i + 1);
  }
  return pi * 4;
}

// 计算圆周率，迭代 1000000 次以获得高精度
const result = calculatePi(1000000);
result.toFixed(10);

