function calculatePi(iterations) {
  let sum = 0;
  for (let i = 0; i < iterations; i++) {
    const denominator = 2 * i + 1;
    const sign = i % 2 === 0 ? 1 : -1;
    sum += sign / denominator;
  }
  return 4 * sum;
}

